  ('judicial-d35ec6db-moex-00037', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '公務員甲明知乙欲申請文件之內容不實，仍收受該申請文件進而加以登載，甲之行為如何論罪？', '["甲成立刑法第213條之公務員登載不實罪", "甲成立刑法第211條偽造公文書罪", "甲成立刑法第211條變造公文書罪", "甲成立刑法第215條之業務登載不實罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00038', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '甲謊稱自己為乙之代理人，以本人乙與代理人甲名義製作租賃契約，甲成立何罪？', '["偽造私文書罪", "偽造公文書罪", "業務登載不實罪", "偽造特種文書罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00039', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '關於強制性交罪，下列敘述何者錯誤？', '["刑法第221條第1項強制性交罪保護被害人之性自主權", "以藥劑犯強制性交罪，其處罰較一般強制性交行為為重", "強制性交罪之強制手段，限於強暴、脅迫之高強度方法", "本罪之被害人不限於婦女"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00040', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '關於妨害家庭罪之敘述，依實務見解，下列何者錯誤？', '["和誘未滿16歲之已婚者，成立和誘有配偶之人罪", "和誘罪係保護監督權人對未成年人之監督權", "父母之一方得未滿7歲子女同意將其帶離，使脫離他方親權並阻隔他方探視監護，成立略誘未成年人罪", "略誘未滿16歲之人，以和誘論"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00041', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '有關刑法賭博罪的敘述，下列何者錯誤？', '["在公共場所或公眾得出入之場所賭博者，成立賭博罪", "意圖營利架設賭博網站供人賭博財物，亦成立供給賭博場所罪", "組頭以自有私人住宅作為簽賭處所，供不特定人前來簽賭，賭客亦成立賭博罪", "賭客透過網路以帳號密碼登入賭博網站，與網站經營者對賭財物，不成立賭博罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00042', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '甲為計程車司機，駕駛計程車時，因與車內乘客聊天，致超車時，不慎撞擊前方機車，致騎乘機車乙人車 倒地，乙跌倒時臉部正好撞到路邊小灌木，致右眼受傷，眼睛視力從1.2減至0.1，且永久無法恢復該眼視 力。甲之行為應如何論罪？', '["過失傷害罪", "過失傷害致重傷害罪", "過失重傷罪", "重傷罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00043', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '關於傷害罪章之罪，下列敘述何者正確？', '["我國刑法並無過失傷害罪", "聚眾鬥毆致人於死或重傷者，在場助勢之人不構成犯罪", "對於未滿18 歲之人，施以凌虐或以他法足以妨害其身心之健全或發育者，雖未有客觀可見之傷口，亦 構成犯罪", "激於義憤犯傷害罪者，其處罰較普通傷害罪為重"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00044', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '房東甲安裝針孔攝影機，偷拍房客乙與男友性交行為之影片，甲事後告訴乙此事，並威脅乙如不與自己一 同外出約會，將公開該影片，乙拒絕甲之要求，甲遂將影片公開於色情網站。甲不成立下列何罪？', '["公然侮辱罪", "竊錄他人非公開活動罪", "強制未遂罪", "散布猥褻物品罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00045', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '有關刑法第27章妨害名譽及信用罪的敘述，下列何者錯誤？', '["誹謗是針對具體事實而為陳述", "對於所誹謗之事，只要能證明其為真實者，即使涉及私德無關公共利益，也是不罰", "以散布文字、圖畫犯誹謗罪，為加重誹謗罪", "所謂意圖散布於眾，係指意圖散發或傳布於不特定之多數人而言"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00046', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '下列何者非屬刑法第307條非法搜索罪所定之行為客體？', '["他人之身體", "他人之建築物", "他人之車輛", "他人之隨身物件"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL)
